+      setAgentProgress(prev => {
+        const next = [...prev];
+        if (simMode === "herd") {
+          for (let i=0; i<AGENT_COUNT; i++) {
+             next[i] = Math.min(100, next[i] + Math.random() * 15 + 10);
+          }
+        } else {
+          for (let i=0; i<AGENT_COUNT; i++) {
+             if (step > i * 4) {
+               next[i] = Math.min(100, next[i] + Math.random() * 15 + 10);
+             }
+          }
+        }
+        progressRef.current = next;
+        return next;
+      });
+
