+        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
+          
+          {/* AGENTS LIST */}
+          <div className="space-y-4">
+            <h5 className="text-xs font-mono text-white/40 mb-2 uppercase tracking-wider">Agent Swarm</h5>
+            {Array(AGENT_COUNT).fill(0).map((_, i) => (
